--
-- Table structure for table `expense_catalog_items`
--

DROP TABLE IF EXISTS `expense_catalog_items`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `expense_catalog_items` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `subsection_id` bigint unsigned NOT NULL,
  `item_name` varchar(255) COLLATE utf8mb4_unicode_ci NOT NULL,
  `chart_of_account_id` int unsigned DEFAULT NULL,
  `pattern_id` bigint unsigned DEFAULT NULL,
  `default_values` json DEFAULT NULL,
  `sort_order` smallint unsigned NOT NULL DEFAULT '1',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `expense_catalog_items_chart_of_account_id_foreign` (`chart_of_account_id`),
  KEY `expense_catalog_items_pattern_id_foreign` (`pattern_id`),
  KEY `expense_catalog_items_subsection_id_sort_order_index` (`subsection_id`,`sort_order`),
