DROP TABLE IF EXISTS `expense_plans`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `expense_plans` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `planning_year_id` bigint unsigned NOT NULL,
  `section_id` bigint unsigned NOT NULL,
  `subsection_id` bigint unsigned DEFAULT NULL,
  `catalog_item_id` bigint unsigned DEFAULT NULL,
  `chart_of_account_id` int unsigned DEFAULT NULL,
  `pattern_id` bigint unsigned DEFAULT NULL,
  `version` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plan_type` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `item_name` varchar(255) COLLATE utf8mb4_unicode_ci DEFAULT NULL,
  `plan_detail` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `detail` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `calculation_values` json DEFAULT NULL,
  `pattern_snapshot` json DEFAULT NULL,
  `created_by` int DEFAULT NULL,
  `updated_by` int DEFAULT NULL,
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `expense_plans_planning_year_id_foreign` (`planning_year_id`),
  KEY `expense_plans_section_id_foreign` (`section_id`),
  KEY `expense_plans_subsection_id_foreign` (`subsection_id`),
  KEY `expense_plans_pattern_id_foreign` (`pattern_id`),
  KEY `expense_plans_created_by_foreign` (`created_by`),
  KEY `expense_plans_updated_by_foreign` (`updated_by`),
  KEY `expense_plans_catalog_item_id_foreign` (`catalog_item_id`),
  KEY `expense_plans_chart_of_account_id_foreign` (`chart_of_account_id`),
  CONSTRAINT `expense_plans_catalog_item_id_foreign` FOREIGN KEY (`catalog_item_id`) REFERENCES `expense_catalog_items` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plans_chart_of_account_id_foreign` FOREIGN KEY (`chart_of_account_id`) REFERENCES `chart_of_accounts` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plans_created_by_foreign` FOREIGN KEY (`created_by`) REFERENCES `users` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plans_pattern_id_foreign` FOREIGN KEY (`pattern_id`) REFERENCES `expense_patterns` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plans_planning_year_id_foreign` FOREIGN KEY (`planning_year_id`) REFERENCES `planning_years` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_plans_section_id_foreign` FOREIGN KEY (`section_id`) REFERENCES `expense_sections` (`id`) ON DELETE CASCADE,
  CONSTRAINT `expense_plans_subsection_id_foreign` FOREIGN KEY (`subsection_id`) REFERENCES `expense_subsections` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_plans_updated_by_foreign` FOREIGN KEY (`updated_by`) REFERENCES `users` (`id`) ON DELETE SET NULL
) ENGINE=InnoDB AUTO_INCREMENT=7024 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

