--
-- Table structure for table `expense_subsections`
--

DROP TABLE IF EXISTS `expense_subsections`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `expense_subsections` (
  `id` bigint unsigned NOT NULL AUTO_INCREMENT,
  `section_id` bigint unsigned NOT NULL,
  `code` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `description` text CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci,
  `default_pattern_id` bigint unsigned DEFAULT NULL,
  `summary_period_count` decimal(10,2) NOT NULL DEFAULT '12.00',
  `display_order` int unsigned NOT NULL DEFAULT '0',
  `is_active` tinyint(1) NOT NULL DEFAULT '1',
  `created_at` timestamp NULL DEFAULT NULL,
  `updated_at` timestamp NULL DEFAULT NULL,
  `parent_id` bigint unsigned DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `expense_subsections_section_code_unique` (`section_id`,`code`),
  KEY `expense_subsections_default_pattern_id_foreign` (`default_pattern_id`),
  CONSTRAINT `expense_subsections_default_pattern_id_foreign` FOREIGN KEY (`default_pattern_id`) REFERENCES `expense_patterns` (`id`) ON DELETE SET NULL,
  CONSTRAINT `expense_subsections_section_id_foreign` FOREIGN KEY (`section_id`) REFERENCES `expense_sections` (`id`) ON DELETE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=1706 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
/*!40101 SET character_set_client = @saved_cs_client */;

